WITH customer_drift AS (SELECT dp.id, dp.plan_date, p.sku, p.name AS product_name, old_c.code AS stored_customer_code, current_c.code AS current_customer_code, delivery_c.code AS delivery_customer_code, COALESCE(dp.planned_qty, 0) AS planned_qty, COALESCE(dp.backlog_qty, 0) AS backlog_qty, COALESCE(dp.actual_qty, 0) AS actual_qty, COALESCE(dp.is_completed, false) AS is_completed, CASE WHEN dp.delivery_customer_id IS NULL AND dp.customer_id IS DISTINCT FROM p.customer_id THEN 'PARENT_CUSTOMER_STALE' WHEN dp.delivery_customer_id IS NOT NULL AND dp.delivery_customer_id IS DISTINCT FROM p.customer_id AND delivery_c.parent_customer_id IS DISTINCT FROM p.customer_id THEN 'VENDOR_OUTSIDE_CURRENT_PARENT' ELSE NULL END AS issue FROM public.delivery_plans dp JOIN public.products p ON p.id = dp.product_id AND p.deleted_at IS NULL LEFT JOIN public.customers old_c ON old_c.id = dp.customer_id LEFT JOIN public.customers current_c ON current_c.id = p.customer_id LEFT JOIN public.customers delivery_c ON delivery_c.id = dp.delivery_customer_id WHERE dp.deleted_at IS NULL) SELECT plan_date, sku, product_name, stored_customer_code, current_customer_code, delivery_customer_code, planned_qty, backlog_qty, actual_qty, is_completed, issue, CASE WHEN actual_qty = 0 AND is_completed = false AND planned_qty + backlog_qty > 0 THEN 'OPEN_AND_AT_RISK' WHEN actual_qty = 0 AND is_completed = false THEN 'OPEN_NO_QTY' ELSE 'HISTORY_DO_NOT_REWRITE' END AS handling FROM customer_drift WHERE issue IS NOT NULL ORDER BY CASE WHEN actual_qty = 0 AND is_completed = false AND planned_qty + backlog_qty > 0 THEN 0 WHEN actual_qty = 0 AND is_completed = false THEN 1 ELSE 2 END, plan_date DESC, sku;
